4	/**
5	 * Hook to call admin-api edge function with current user's JWT.
6	 * Surfaces real error details (status + body) instead of generic messages.
7	 */
8	export function useAdminApi() {
9	  const call = useCallback(async (action: string, payload: Record<string, unknown> = {}) => {
10	    // Use getUser() to force token refresh if expired, then fall back to getSession()
11	    let accessToken: string | undefined;
12	    try {
13	      const { data: { session } } = await supabase.auth.getSession();
14	      accessToken = session?.access_token;
15	      // If token looks expired (JWT exp check), force refresh
16	      if (accessToken) {
17	        try {
18	          const parts = accessToken.split(".");
19	          if (parts.length === 3) {
20	            const payload64 = parts[1].replace(/-/g, "+").replace(/_/g, "/");
21	            const claims = JSON.parse(atob(payload64));
22	            if (claims.exp && claims.exp * 1000 < Date.now() + 30_000) {
23	              // Token expires within 30s — force refresh
24	              const { data: { session: refreshed } } = await supabase.auth.refreshSession();
25	              if (refreshed?.access_token) accessToken = refreshed.access_token;
26	            }
27	          }
28	        } catch { /* JWT parse failed, proceed with existing token */ }
29	      }
30	    } catch {
31	      accessToken = undefined;
32	    }
33	    if (!accessToken) throw new Error("Not authenticated");
34	
35	    const MAX_RETRIES = 2;
36	    let lastError: Error | null = null;
37	
38	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
39	      const { data, error } = await supabase.functions.invoke("admin-api", {
40	          body: { action, ...payload },
41	          headers: { Authorization: `Bearer ${accessToken}` },
42	        });
43	
44	        if (error) {
45	          // Extract real error details from FunctionsHttpError
46	          let detailedMsg = error.message || "Admin API call failed";
47	          let status = 0;
48	          try {
49	            const ctx = (error as any).context;
50	            if (ctx && typeof ctx.status === "number") {
51	              status = ctx.status;
52	              const bodyText = typeof ctx.text === "function" ? await ctx.text() : "";
53	              const bodyPreview = bodyText.slice(0, 400);
54	              const looksHtml = /<!doctype|<html|<head>/i.test(bodyText);
55	              let parsed: any = null;
56	              try { parsed = JSON.parse(bodyText); } catch { /* not JSON */ }
57	
58	              if (looksHtml) {
59	                detailedMsg = `[${ctx.status}] Upstream gateway returned HTML instead of JSON (transient infrastructure error). Please retry.`;
60	              } else {
61	                const serverError = parsed?.error || bodyPreview || detailedMsg;
62	                detailedMsg = `[${ctx.status}] ${serverError}`;
63	              }
64	            }
65	          } catch { /* fallback to original message */ }
66	
67	          const isTransient =
68	            [500, 502, 503, 504, 520, 522, 524].includes(status) ||
69	            /internal server error|gateway|transient|timeout|failed to fetch|network/i.test(detailedMsg);
70	          if (isTransient && attempt < MAX_RETRIES) {
71	            lastError = new Error(detailedMsg);
72	            await new Promise(r => setTimeout(r, 500 * (attempt + 1)));
73	            continue;
74	          }
75	          throw new Error(detailedMsg);
76	        }
77	
78	        if (data && !data.ok) throw new Error(data.error || "Admin API returned error");
79	        return data;
80	    }
81	
82	    throw lastError || new Error("Admin API call failed after retries");
83	  }, []);
84	
85	  return { call };
86	}
